// Initial implementation of Remember Me feature

function setRememberMe(username, passwordHash) {
    const expiryDate = new Date();
    expiryDate.setDate(expiryDate.getDate() + 30);
    document.cookie = `username=${encodeURIComponent(username)}; expires=${expiryDate.toUTCString()}; path=/`;
    document.cookie = `passwordHash=${encodeURIComponent(passwordHash)}; expires=${expiryDate.toUTCString()}; path=/`;
}

function getRememberMeCredentials() {
    const cookies = document.cookie.split(';').map(cookie => cookie.trim());
    const usernameCookie = cookies.find(cookie => cookie.startsWith('username='));
    const passwordHashCookie = cookies.find(cookie => cookie.startsWith('passwordHash='));
    
    if (usernameCookie && passwordHashCookie) {
        return {
            username: decodeURIComponent(usernameCookie.split('=')[1]),
            passwordHash: decodeURIComponent(passwordHashCookie.split('=')[1])
        };
    }
    return null;
}

